{
  pkgs,
  sops-nix,
  stablePkgs,
  ...
}:
let
  cfg = import ../../config/default.nix;
  userPackages = import ../../config/packages-user.nix { inherit pkgs stablePkgs; };
  linuxUserPackages = import ../../os/linux/packages-user.nix { inherit pkgs; };
  systemPackages = import ../../config/packages.nix { inherit pkgs; };
  #wallpaperPkg = pkgs.callPackage ../../wallpaper { };
in
{

  nix.settings.experimental-features = [
    "nix-command"
    "flakes"
  ];

  _module.args = {
    inherit (cfg) username;
    userPackages = userPackages ++ linuxUserPackages;
  };

  # @todo - maybe split nixos config into a separate distro
  imports = [
    ./dictation.nix
    ../../os/default.nix
    ../../os/nixos/bootloader.nix
    ../../os/nixos/gc.nix
    ../../os/nixos/trustme.nix
    ../../os/nixos/unfree.nix
    ../../os/linux/virt.nix
    ../../os/linux/user.nix
    {
      home-manager = {
        # @todo - maybe make waybar, mako, rofi, etc become deps of sway
        useGlobalPkgs = true;
        useUserPackages = true;
        extraSpecialArgs = {
          inputs = { inherit sops-nix; };
        };
        users.${cfg.username}.imports = [
          ../../home-manager
          ../../home-manager/auggie
          ../../home-manager/beets
          ../../home-manager/claude-code
          ../../home-manager/codex
          ../../home-manager/crush
          ../../home-manager/cursor-cli
          ../../home-manager/kitty
          ../../home-manager/firefox
          ../../home-manager/git
          ../../home-manager/mako
          ../../home-manager/mcp
          ../../home-manager/mpd
          ../../home-manager/nextcloud-sync
          ../../home-manager/nodejs
          ../../home-manager/nvim
          ../../home-manager/opencode
          ../../home-manager/rofi
          ../../home-manager/sops
          ../../home-manager/ssh
          ../../home-manager/sway
          ../../home-manager/tmux
          ../../home-manager/vale
          ../../home-manager/waybar
          ../../home-manager/zsh
        ];
      };
    }
  ];

  environment = {
    shells = with pkgs; [
      bash
      zsh
    ];
    inherit systemPackages;
  };

  programs = {
    _1password.enable = true;
    _1password-gui = {
      enable = true;
      polkitPolicyOwners = [ "${cfg.username}" ];
    };
    firefox = {
      enable = true;
      policies = {
        DisableTelemetry = true;
        DisableFirefoxStudies = true;
        DisablePocket = true;
        DisableFirefoxAccounts = false;
        DisableFormHistory = false;
        DontCheckDefaultBrowser = true;
        OfferToSaveLogins = false;

        ExtensionSettings = {
          # uBlock Origin
          "uBlock0@raymondhill.net" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/ublock-origin/latest.xpi";
            installation_mode = "force_installed";
          };
          # 1Password
          "{d634138d-c276-4fc8-924b-40a0ea21d284}" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/1password-x-password-manager/latest.xpi";
            installation_mode = "force_installed";
          };
          # Vimium
          "{d7742d87-e61d-4b78-b8a1-b469842139fa}" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/vimium-ff/latest.xpi";
            installation_mode = "force_installed";
          };
          # SponsorBlock
          "sponsorBlocker@ajay.app" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/sponsorblock/latest.xpi";
            installation_mode = "force_installed";
          };
          # Facebook Container
          "@contain-facebook" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/facebook-container/latest.xpi";
            installation_mode = "force_installed";
          };
          # Enhancer for YouTube
          "enhancerforyoutube@maximerf.addons.mozilla.org" = {
            install_url = "https://addons.mozilla.org/firefox/downloads/latest/enhancer-for-youtube/latest.xpi";
            installation_mode = "force_installed";
          };
        };
      };
    };

    gnupg.agent = {
      enable = true;
      pinentryPackage = pkgs.pinentry-curses;
    };

    obs-studio = {
      enable = true;
      plugins = with pkgs.obs-studio-plugins; [
        wlrobs
        obs-backgroundremoval
        obs-pipewire-audio-capture
        obs-gstreamer
        obs-vkcapture
      ];
    };
    #regreet = {
    #  enable = true;
    #  settings = {
    #    background = {
    #      path =
    #        "${wallpaperPkg}/nix-wallpaper-nineish-catppuccin-macchiato.png";
    #      fit = "Cover";
    #    };
    #    GTK = { application_prefer_dark_theme = true; };
    #    appearance = { greeting_msg = "Mr. Anderson, Welcome back!"; };
    #  };
    #};
    steam.enable = true;
    sway.enable = true;
    virt-manager.enable = true;
    zsh.enable = true;
  };

  # recommended so PipeWire gets realtime priority
  security.rtkit.enable = true;

  services = {
    blueman.enable = true;
    gnome.gnome-keyring.enable = true;
    libinput.enable = true;
    mpd = {
      enable = true;
      user = "${cfg.username}";
      group = "users";
      settings = {
        music_directory = "/home/${cfg.username}/Music";
        audio_output = [
          {
            type = "pipewire";
            name = "PipeWire Sound Server";
          }
        ];
      };
    };
    openssh.enable = true;
    pipewire = {
      enable = true;
      alsa.enable = true;
      alsa.support32Bit = true;
      pulse.enable = true;
      wireplumber.enable = true;
    };
    greetd = {
      enable = true;
      settings = {
        default_session = {
          command = "${pkgs.tuigreet}/bin/tuigreet --time --cmd 'sway --unsupported-gpu'";
          user = "${cfg.username}";
        };
      };
    };
    upower.enable = true;

    transmission = {
      enable = true;
      package = pkgs.transmission_4;
      user = "${cfg.username}";
      group = "users";
      webHome = pkgs.flood-for-transmission;
      openRPCPort = true;
      settings = {
        rpc-bind-address = "0.0.0.0";
        rpc-whitelist-enabled = false;
        download-dir = "/home/${cfg.username}/Downloads";
        incomplete-dir = "/home/${cfg.username}/Downloads/.incomplete";
        incomplete-dir-enabled = true;
      };
    };
  };

  systemd = {
    # Create transmission download directories
    tmpfiles.rules = [
      "d /home/${cfg.username}/Downloads 0755 ${cfg.username} users -"
      "d /home/${cfg.username}/Downloads/.incomplete 0755 ${cfg.username} users -"
    ];

    # Set XDG_RUNTIME_DIR for MPD to connect to PipeWire
    services.mpd.environment = {
      XDG_RUNTIME_DIR = "/run/user/1000";
    };

    # Enable lingering for the ${cfg.username} user so the service starts at boot
    # even when the user is not logged in
    user.services."user@${cfg.username}".enable = true;
  };

  xdg.portal.enable = true;

  system.stateVersion = "25.05";

}

